import{_ as r,C as a,o as c,c as n,j as t,a as o,E as s,ag as i}from"./chunks/framework.HG0H2VLS.js";const f=JSON.parse('{"title":"ControlScreen","description":"","frontmatter":{},"headers":[],"relativePath":"cc-templates/control-screen.md","filePath":"cc-templates/control-screen.md"}'),l={name:"cc-templates/control-screen.md"};function p(h,e,m,u,b,g){const d=a("ComponentDemo");return c(),n("div",null,[e[0]||(e[0]=t("hr",null,null,-1)),e[1]||(e[1]=t("h2",{id:"title-controlscreen",tabindex:"-1"},[o("title: ControlScreen "),t("a",{class:"header-anchor",href:"#title-controlscreen","aria-label":'Permalink to "title: ControlScreen"'},"​")],-1)),e[2]||(e[2]=t("h1",{id:"controlscreen",tabindex:"-1"},[o("ControlScreen "),t("a",{class:"header-anchor",href:"#controlscreen","aria-label":'Permalink to "ControlScreen"'},"​")],-1)),s(d,{src:"/demos/src/cc/templates/ControlScreen/ControlScreen.html"}),e[3]||(e[3]=i('<h2 id="composed-components" tabindex="-1">Composed components <a class="header-anchor" href="#composed-components" aria-label="Permalink to &quot;Composed components&quot;">​</a></h2><p>ControlScreen owns <strong>only the app-shell layout</strong>. Every visual block is rendered by an existing component or pattern via its own CSS:</p><table tabindex="0"><thead><tr><th>Source</th><th>Role in ControlScreen</th></tr></thead><tbody><tr><td><code>src/cc/patterns/SidebarMenu/</code> + <code>sidebar-menu.js</code></td><td>Left app rail + menu panel. Desktop + Mobile composites both included in DOM, swapped via <code>@media (max-width: 767px)</code>. Both auto-bind on DOMContentLoaded.</td></tr><tr><td><code>src/cc/patterns/HeaderGroup/</code> (composes <code>TopNavigation</code> + <code>Header</code>)</td><td>Top chrome. Uses the <code>cc-header--control</code> modifier — greeting + Logout/View Site CTAs.</td></tr><tr><td><code>src/components/Alert/</code> (<code>alert--cta</code> + <code>alert--warning</code>)</td><td>Development-mode banner with Switch Mode CTA.</td></tr><tr><td><code>src/patterns/StatCard/</code> × 2</td><td>&quot;Key Features&quot; + &quot;Help Guides&quot; cards in the 3-col row.</td></tr><tr><td><code>src/patterns/UpgradeCard/</code></td><td>Version + Update CTA — third cell of the 3-col row.</td></tr><tr><td><code>src/components/Select/</code> (<code>sel sel__control--sm</code>)</td><td>&quot;Select Zone&quot; dropdown.</td></tr><tr><td><code>src/patterns/Chart/</code> × 2 + Chart.js CDN</td><td>&quot;Page Views&quot; (multi-line) + &quot;Users&quot; (single-line area).</td></tr><tr><td><code>src/components/Datatables/</code> (Whos Online variant — base <code>.datatables</code>, no <code>--mobile-scroll</code>)</td><td>Members table. <code>--mobile-scroll</code> modifier is for fixed-width mobile mockups and pins <code>max-width: 24rem</code>; base <code>.datatables</code> fills 100% of its container and the inner <code>.datatables__body</code> auto-scrolls horizontally when the table is wider than the viewport.</td></tr></tbody></table><p>Transitive deps loaded via <code>&lt;link&gt;</code>: Button, Breadcrumb, Dropdown, DropdownItem, Portraits, Avatar, NotificationBadge, Toggle, ThemeToggle, Input, Table, MainMenuItem.</p><h2 id="js-interactivity" tabindex="-1">JS / Interactivity <a class="header-anchor" href="#js-interactivity" aria-label="Permalink to &quot;JS / Interactivity&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>Role</th><th>Binding</th></tr></thead><tbody><tr><td><code>src/cc/patterns/SidebarMenu/sidebar-menu.js</code></td><td>Rail-button → panel toggle, hover-flyout (desktop), mobile ellipsis expand, search filter, MainMenuItem submenu toggle, CRM &quot;show more&quot; toggle.</td><td>Auto-binds every <code>.cc-sidebar-menu</code> on DOMContentLoaded — both composites bind independently.</td></tr><tr><td>Chart.js (CDN)</td><td>Renders the two chart canvases.</td><td>Inline init in the template footer.</td></tr><tr><td>Lucide (CDN)</td><td>Icon rendering.</td><td><code>lucide.createIcons()</code> after load.</td></tr><tr><td><code>dark-mode-toggle.js</code></td><td>Wires the <code>data-theme</code> toggle if any UI surfaces it.</td><td>Auto-init from head script.</td></tr></tbody></table><p>No new JS module is authored by the template.</p><h2 id="known-limitations-composed-component-carryover" tabindex="-1">Known limitations (composed-component carryover) <a class="header-anchor" href="#known-limitations-composed-component-carryover" aria-label="Permalink to &quot;Known limitations (composed-component carryover)&quot;">​</a></h2><ul><li><strong>Composed components still use viewport <code>@media</code>, not the container.</strong> The template&#39;s own reflow is container-query driven, but every composed pattern it embeds (<code>alert</code>, <code>cc-top-navigation</code>, <code>cc-header</code> with <code>--control</code>, <code>Datatables</code>) carries its own internal <code>@media (max-width: 767px)</code> blocks. Those react to viewport width only. Practical effect: in a narrow-column-but-wide-viewport scenario (e.g. desktop with the menu panel docked) the template grids correctly stack to one column, but the embedded components stay in desktop dress — Alert keeps its CTA inline (not stacked under the message), <code>cc-header--control</code> keeps the &quot;Hi&quot; prefix and full button labels, Datatables keeps its full-width toolbar gap. Fully container-aware behaviour would require each component&#39;s <code>@media</code> blocks to be refactored to <code>@container</code> — a separate sweep, outside this template build.</li><li><strong>StatCard icon-wrap colour does not theme to CC brand.</strong> <code>StatCard.css</code> hardcodes the icon-square background to <code>#2563eb</code> (Blue/600 primitive, user-approved gap on the StatCard build). Figma&#39;s Control Screen renders the same square in a CC teal hue. Fixing this needs a StatCard-side change (replace the primitive with a <code>--ai-surface-brand</code>-aware token or introduce a <code>[data-brand=&quot;cc&quot;]</code> override) — out of scope for the template build. Flagged here so the next StatCard review can address.</li><li><strong>Select label-above-control on mobile.</strong> Figma mobile shows the Select Zone label INLINE with the dropdown (label-left, control-right on the same row). The current Select component renders label above control. Matching the Figma exactly would require overriding the Select layout — kept default per &quot;use built versions, no deviating&quot;.</li></ul><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><p>Template-owned classes only (every other class belongs to a composed component):</p><table tabindex="0"><thead><tr><th>Class</th><th>Role</th></tr></thead><tbody><tr><td><code>.control-screen</code></td><td>Body root. <code>display: flex; height: 100vh</code>.</td></tr><tr><td><code>.control-screen__sidebar</code></td><td>Wrapper for a SidebarMenu composite. <code>flex: 0 0 auto; height: 100vh</code>.</td></tr><tr><td><code>.control-screen__sidebar--desktop</code></td><td>Visible at ≥768px.</td></tr><tr><td><code>.control-screen__sidebar--mobile</code></td><td>Visible at &lt;768px.</td></tr><tr><td><code>.control-screen__main</code></td><td>Flex column filling remainder. <code>overflow: hidden</code>.</td></tr><tr><td><code>.control-screen__chrome</code></td><td>Sticky-equivalent top band hosting <code>cc-header-group</code>.</td></tr><tr><td><code>.control-screen__page</code></td><td>Scroll container. <code>flex: 1 1 auto; overflow-y: auto</code>.</td></tr><tr><td><code>.control-screen__cards</code></td><td>3-col → 1-col grid. UpgradeCard <code>order: -1</code> at mobile.</td></tr><tr><td><code>.control-screen__zone-row</code></td><td>Select Zone + Analysis Dashboard link, space-between.</td></tr><tr><td><code>.control-screen__analysis-link</code></td><td>Right-side text link (brand colour + arrow icon). Two copies in the DOM — <code>--desktop</code> (inside <code>.control-screen__zone-row</code>, visible ≥768px) and <code>--mobile</code> (standalone block after <code>.control-screen__charts</code>, visible &lt;768px), matching the Figma&#39;s mobile placement (between charts and Whos Online).</td></tr><tr><td><code>.control-screen__charts</code></td><td>2-col → 1-col grid for Chart cards.</td></tr><tr><td><code>.control-screen__section</code></td><td>Wrapper frame: section heading + section body.</td></tr><tr><td><code>.control-screen__section-head</code></td><td>Flex row: title left, meta right (stacks on mobile).</td></tr><tr><td><code>.control-screen__section-title</code></td><td>h2 — &quot;Who&#39;s Online&quot;.</td></tr><tr><td><code>.control-screen__section-meta</code></td><td>Subtitle — &quot;78 Members Online (…)&quot;.</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><p>The template introduces no new tokens. Tokens used at template scope:</p><table tabindex="0"><thead><tr><th>Token</th><th>Where</th></tr></thead><tbody><tr><td><code>--ai-surface-secondary</code></td><td><code>.control-screen</code> body bg</td></tr><tr><td><code>--ai-surface-primary</code></td><td><code>.control-screen__chrome</code> bg</td></tr><tr><td><code>--ai-border-secondary</code></td><td><code>.control-screen__chrome</code> bottom border</td></tr><tr><td><code>--ai-spacing-7</code></td><td>Default page padding + gap (desktop)</td></tr><tr><td><code>--ai-spacing-5</code></td><td>Card row gap + mobile page padding/gap</td></tr><tr><td><code>--ai-spacing-6</code></td><td>Charts row gap</td></tr><tr><td><code>--ai-spacing-4</code></td><td>Section head gap</td></tr><tr><td><code>--ai-spacing-2</code></td><td>Mobile section head gap, link icon gap</td></tr><tr><td><code>--ai-font-body</code> / <code>--ai-font-title</code></td><td>Body / title font families</td></tr><tr><td><code>--ai-font-fluid-lg</code></td><td>Section heading size</td></tr><tr><td><code>--ai-font-fixed-xs</code></td><td>Section meta line size</td></tr><tr><td><code>--ai-font-fixed-sm</code> + <code>--ai-font-semibold</code></td><td>Analysis Dashboard link</td></tr><tr><td><code>--ai-text-primary</code> / <code>--ai-text-contrast</code> / <code>--ai-text-brand</code></td><td>Text colours</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None at template scope. Composed components carry their own approved gaps (see each component&#39;s <code>figma-notes.md</code>).</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Default state on load:</strong> the Desktop SidebarMenu has the Control panel docked open (<code>Menu Open</code> Desktop variant). Mobile defaults to rail-only (<code>Menu Collapsed</code> Mobile variant). These align with the four Figma variants.</li><li><strong>Responsive breakpoint:</strong> template-level layout reflow uses <strong><code>@container cs-page (max-width: 767px)</code></strong> — the page reacts to the actual content column&#39;s width, not the viewport. This matters because the docked SidebarMenu (rail + 280px panel ≈ 336px) can shrink the main column below 768px on a wide screen, and the page should still reflow.</li><li><strong>Device-class swap stays on <code>@media</code>:</strong> which SidebarMenu composite (<code>--desktop</code> vs <code>--mobile</code>) is rendered is a device-class decision (the mobile rail has structurally different children — Ellipsis-toggled extras), so the swap is keyed off viewport <code>@media (max-width: 767px)</code>. Even when the desktop column shrinks to &lt;768px because its own menu panel is docked, the desktop rail stays.</li><li><strong>Sidebar composite swap:</strong> Desktop and Mobile SidebarMenu composites are both in the DOM with unique panel IDs (<code>cc-d-*</code> vs <code>cc-m-*</code>) so the auto-bound JS doesn&#39;t clash; CSS shows one and hides the other based on viewport.</li><li><strong>Mobile content order:</strong> UpgradeCard precedes the two StatCards on mobile per Figma (visible in <code>cs-mobile-collapsed.png</code>). Implemented via <code>order: -1</code> on <code>.control-screen__cards .upgrade-card</code> so the HTML order stays semantic.</li><li><strong>No component CSS overrides:</strong> the template uses every composed component verbatim with no scoped customisations. Future Figma changes to any composed component will surface here automatically.</li><li><strong>Demo content sourcing:</strong> every block reuses copy from its own demo for now — to be amended later with Figma-faithful labels (Susan Kerrigan / Maria Mellor / 78 Members / Version 8.0.33.10 etc. already match; chart numbers + StatCard icon choice may be refined).</li></ul>',19))])}const v=r(l,[["render",p]]);export{f as __pageData,v as default};
